#include<bits/stdc++.h>
using namespace std;
int n,x[10010],y[10010];
double dist(int i,int j)
{
    return sqrt(pow(x[i]-x[j],2)+pow(y[i]-y[j],2));
}
double dp[10010][31];
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&x[i],&y[i]);
        for(int j=0;j<=30;j++)
        {
            dp[i][j]=1e18;
        }
    }
    dp[1][0]=0;
    for(int i=2;i<=n;i++)
    {
        for(int j=0;j<min(i,30);j++)
        {
            dp[i][j]=min(dp[i][j],dp[i-1][j]+dist(i-1,i));
        }
        for(int j=max(1,i-30);j<i;j++)
        {
            for(int k=0;k<=min(30,i-1);k++)
            {
                if(k-i+j+1>=0)
                {
                    dp[i][k]=min(dp[i][k],dp[j][k-i+j+1]+dist(i,j));
                }
            }
        }
    }
    double ans=1e20;
    for(int i=1;i<=30;i++)
    {
        ans=min(ans,dp[n][i]+(1<<(i-1)));
    }
    cout<<fixed<<setprecision(10)<<ans;
    return 0;
}
